import{_ as a,o as r,c as e,ai as d}from"./chunks/framework.SowO7O0D.js";const p=JSON.parse('{"title":"第四课：什么是指数？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/04-what-is-index.md","filePath":"guide/04-what-is-index.md","lastUpdated":0}'),l={name:"guide/04-what-is-index.md"};function o(i,t,n,h,s,b){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="第四课-什么是指数" tabindex="-1">第四课：什么是指数？ <a class="header-anchor" href="#第四课-什么是指数" aria-label="Permalink to “第四课：什么是指数？”">​</a></h1><p>炒股的人天天说&quot;大盘今天涨了&quot;、&quot;创业板指创新高&quot;，这个&quot;指数&quot;到底是什么？</p><h2 id="一句话理解指数" tabindex="-1">一句话理解指数 <a class="header-anchor" href="#一句话理解指数" aria-label="Permalink to “一句话理解指数”">​</a></h2><p><strong>指数就是市场的&quot;平均成绩单&quot;。</strong></p><p>把很多只股票按一定规则打包在一起，算出一个综合分数，这个分数就是指数。</p><h2 id="生活比喻" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻" aria-label="Permalink to “生活比喻”">​</a></h2><p>想象你们班有50个同学，期末考了5门课：</p><ul><li><strong>上证指数</strong> = 全班所有人的平均分（所有股票的综合表现）</li><li><strong>沪深300</strong> = 全班成绩最好的30个人的平均分（最优秀的300只股票）</li><li><strong>创业板指</strong> = 艺术特长班的平均分（创新成长型公司）</li></ul><h2 id="a股主要指数一览" tabindex="-1">A股主要指数一览 <a class="header-anchor" href="#a股主要指数一览" aria-label="Permalink to “A股主要指数一览”">​</a></h2><h3 id="上证指数-000001" tabindex="-1">上证指数（000001） <a class="header-anchor" href="#上证指数-000001" aria-label="Permalink to “上证指数（000001）”">​</a></h3><p><strong>全称：上海证券交易所综合股价指数</strong></p><ul><li>包含了在上海证券交易所上市的<strong>所有股票</strong></li><li>1991年发布，是中国历史最悠久的指数</li><li>你在新闻里听到&quot;大盘跌破3000点&quot;，说的就是它</li></ul><blockquote><p>📊 <strong>上证指数 ≈ A股整体温度计</strong></p></blockquote><h3 id="深证指数-399001" tabindex="-1">深证指数（399001） <a class="header-anchor" href="#深证指数-399001" aria-label="Permalink to “深证指数（399001）”">​</a></h3><p><strong>全称：深圳证券交易所成分股价指数</strong></p><ul><li>包含了在深圳证券交易所上市的<strong>所有股票</strong></li><li>深圳市场以<strong>中小盘、创业板</strong>为主</li><li>整体风格比上证指数更&quot;激进&quot;</li></ul><h3 id="沪深300-000300-399300" tabindex="-1">沪深300（000300 / 399300） <a class="header-anchor" href="#沪深300-000300-399300" aria-label="Permalink to “沪深300（000300 / 399300）”">​</a></h3><p><strong>最最重要的指数，没有之一。</strong></p><ul><li>上海+深圳两家交易所里，<strong>市值最大、流动性最好</strong>的300只股票</li><li>相当于&quot;全校前300名尖子生&quot;</li><li>A股最具代表性的核心资产</li></ul><blockquote><p>💡 如果你不知道买什么，买<strong>沪深300ETF</strong>（代码510300）就对了，它打包了中国最好的300家公司。</p></blockquote><h3 id="创业板指-399006" tabindex="-1">创业板指（399006） <a class="header-anchor" href="#创业板指-399006" aria-label="Permalink to “创业板指（399006）”">​</a></h3><ul><li>专门跟踪<strong>创业板</strong>100只最大市值股票</li><li>创业板主要是：<strong>创新型、成长型公司</strong>（新能源、医药、科技为主）</li><li>波动比主板大，机会多、风险也高</li></ul><blockquote><p>🚨 创业板股票涨跌幅是±20%，比主板风险更大。</p></blockquote><h3 id="科创50-000688" tabindex="-1">科创50（000688） <a class="header-anchor" href="#科创50-000688" aria-label="Permalink to “科创50（000688）”">​</a></h3><ul><li>科创板（2019年新开）里<strong>市值最大的50只股票</strong></li><li>科创板定位：<strong>硬科技</strong>企业（芯片、人工智能、生物医药等）</li><li>代表中国科技未来方向</li></ul><h2 id="指数的计算原理" tabindex="-1">指数的计算原理 <a class="header-anchor" href="#指数的计算原理" aria-label="Permalink to “指数的计算原理”">​</a></h2><p>不需要深究，但要知道：<strong>指数是加权平均</strong>。</p><p>大市值公司对指数影响更大（权重更高）。</p><h3 id="举例" tabindex="-1">举例 <a class="header-anchor" href="#举例" aria-label="Permalink to “举例”">​</a></h3><p>假设一个指数只有2只股票：</p><ul><li>苹果公司市值1000亿，权重90%</li><li>小公司市值100亿，权重10%</li></ul><p>如果苹果涨10%，指数大概涨9%；如果小公司涨10%，指数只涨1%。</p><blockquote><p>所以常说&quot;大盘涨了，但我的股票没涨&quot;——很可能你买的是市值小的股票，不在权重股里。</p></blockquote><h2 id="为什么指数很重要" tabindex="-1">为什么指数很重要？ <a class="header-anchor" href="#为什么指数很重要" aria-label="Permalink to “为什么指数很重要？”">​</a></h2><h3 id="_1-看大盘操作" tabindex="-1">1. 看大盘操作 <a class="header-anchor" href="#_1-看大盘操作" aria-label="Permalink to “1. 看大盘操作”">​</a></h3><p>新手最好<strong>大盘环境好的时候才操作</strong>，单边下跌的熊市减少交易。</p><table tabindex="0"><thead><tr><th>大盘环境</th><th>操作建议</th></tr></thead><tbody><tr><td>大盘连续上涨</td><td>可以积极一点</td></tr><tr><td>大盘震荡</td><td>控制仓位，少动</td></tr><tr><td>大盘连续下跌</td><td>多看少动，不抄底</td></tr></tbody></table><h3 id="_2-判断市场温度" tabindex="-1">2. 判断市场温度 <a class="header-anchor" href="#_2-判断市场温度" aria-label="Permalink to “2. 判断市场温度”">​</a></h3><table tabindex="0"><thead><tr><th>指数点位</th><th>市场状态</th></tr></thead><tbody><tr><td>上证 &gt; 3500</td><td>偏热</td></tr><tr><td>上证 3000-3500</td><td>正常</td></tr><tr><td>上证 &lt; 3000</td><td>偏冷（历史上在这个区间机会多）</td></tr></tbody></table><h3 id="_3-买指数基金" tabindex="-1">3. 买指数基金 <a class="header-anchor" href="#_3-买指数基金" aria-label="Permalink to “3. 买指数基金”">​</a></h3><p>如果你不知道买什么股票，可以直接买指数基金（ETF），省去选股的烦恼。</p><h2 id="主要指数代码速查" tabindex="-1">主要指数代码速查 <a class="header-anchor" href="#主要指数代码速查" aria-label="Permalink to “主要指数代码速查”">​</a></h2><table tabindex="0"><thead><tr><th>指数名称</th><th>代码</th><th>交易所</th><th>涨跌幅</th></tr></thead><tbody><tr><td>上证指数</td><td>000001</td><td>上交所</td><td>±10%</td></tr><tr><td>深证指数</td><td>399001</td><td>深交所</td><td>±10%</td></tr><tr><td>沪深300</td><td>000300</td><td>两所</td><td>±10%</td></tr><tr><td>创业板指</td><td>399006</td><td>深交所</td><td>±20%</td></tr><tr><td>科创50</td><td>000688</td><td>上交所</td><td>±20%</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>沪深300指数最近点位是4200点，比去年同期涨了15%。这说明什么？应该开心还是担心？</p></blockquote><hr><p><strong>下一课预告</strong>：了解了指数，下一课学习<strong>板块与行业</strong>——什么是热点板块、如何看资金流向。</p>',47)])])}const u=a(l,[["render",o]]);export{p as __pageData,u as default};
